import React, { FunctionComponent, useState } from "react";
import { Button, H1, H6, InputGroup } from "@blueprintjs/core";
import { observer } from "mobx-react";
import axios from "axios";
import { OurToaster } from "./OurToaster";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import { Position } from "@blueprintjs/core/lib/esm/common/position";
import { DateInput, IDateFormatProps } from "@blueprintjs/datetime";
import moment from "moment";

export const Pending: FunctionComponent = observer(() => {
  const [date, setDate] = useState(new Date());
  const [language, setLanguage] = useState("fr");
  const [lastName, setLastName] = useState("");
  const [mail, setMail] = useState("");
  const [mailConfirm, setMailConfirm] = useState("");
  const [password, setPassword] = useState("");
  const [passwordConfirm, setPasswordConfirm] = useState("");

  const jsDateFormatter: IDateFormatProps = {
    // note that the native implementation of Date functions differs between browsers
    formatDate: date => date.toLocaleDateString(),
    parseDate: str => new Date(str),
    placeholder: "M/D/YYYY",
  };

  function formatDate(date: Date, locale?: any): string {
    return "string;"
  }

  function parseDate(date: Date, locale?: any): Date {
    return new Date();
  }

  function getMomentFormatter(format: string): IDateFormatProps {
    // note that locale argument comes from locale prop and may be undefined
    return {
      formatDate: (date, locale) =>
        moment(date)
          .locale(language)
          .format(format),
      parseDate: (str, locale) =>
        moment(str, format)
          .locale(language)
          .toDate(),
      placeholder: format
    };
  }

  function registerSubmit(e: any): void {
    e.preventDefault();
    if (formIsCorrect()) {
      axios
        .post(`http://localhost:5000/users_pending`, {
          id: null
          //role: "pending"
        })
        .then(() => {
          OurToaster.show({
            message:
              "User successfully created ! You can now log in with your login and your password.",
            intent: Intent.SUCCESS,
            timeout: 30000
          });
          //setFirstName("");
        })
        .catch(error => {
          console.log(error);
        });
    }
  }

  function formIsCorrect(): boolean {
    if (!mail.match(/^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/)) {
      OurToaster.show({
        message: "Mail address isn't valid.",
        intent: Intent.DANGER
      });
      return false;
    }
    if (mail !== mailConfirm) {
      OurToaster.show({
        message: "Mail and mail confirm must be equals !",
        intent: Intent.DANGER
      });
      return false;
    }
    if (
      !password.match(
        /^(?=.*[a-z])(?=.*[A-Z])(?=.*[0-9])(?=.*[!@#\$%\^&\*])(?=.{8,})/
      )
    ) {
      OurToaster.show({
        message:
          "Password need more complexity ! It must be more than 8 characters, with one digit, one" +
          " upper case letter and one special symbol !",
        intent: Intent.DANGER,
        timeout: 10000
      });
      return false;
    }
    if (password !== passwordConfirm) {
      OurToaster.show({
        message: "Password and password confirm must be equals !",
        intent: Intent.DANGER
      });
      return false;
    }
    return true;
  }

  function validateForm(): boolean {
    return mail.length > 0;
  }

  return (
    <div className="body">
      <DateInput {...jsDateFormatter} />
      <div className="connected-body">
        <div className="curve-border">
          <div className="fx -c center">
            <div>
              <H1 className="title-primary">Welcome to Heabank !</H1>
              <H6 className="title-primary">
                Hello dear customer, to finalize your registration, please fill
                in the various fields below. A banker will then be in charge of
                your file in order to process your registration request. You
                will be able to reconnect whenever you want to follow the status
                of your application.
              </H6>
            </div>
            <div className="fx -r center">
              <div>
                <form onSubmit={registerSubmit}>
                  <div className="login-inputgroup fx -c">
                    <DateInput
                      {...getMomentFormatter("LL")}
                      placeholder="Date of birth"
                      value={date}
                      onChange={(e: any) => setDate(e.currentTarget.value)}
                      locale={language}
                    />
                    {/*
                    <DateInput
                      value={date}
                      placeholder="Date of birth"
                      onChange={(e: any) => setDate(e.currentTarget.value)}
                      popoverProps={{ position: Position.BOTTOM }}
                    />*/}
                    {/*<DateInput
                        formatDate={date => date.toLocaleString()}
                        onChange={(e: any) => setDate(e.currentTarget.value)}
                        parseDate={str => new Date(str)}
                        placeholder={"M/D/YYYY"}
                        value={date}
                    />*/}
                    <InputGroup
                        type="date"
                        placeholder="Date"
                        required={true}
                        value={lastName}
                        onChange={(ev: any) =>
                            setLastName(ev.currentTarget.value)
                        }
                    />
                    <DateInput {...jsDateFormatter} />
                    <InputGroup
                      placeholder="File..."
                      required={true}
                      value={lastName}
                      onChange={(ev: any) =>
                        setLastName(ev.currentTarget.value)
                      }
                    />
                  </div>
                  <div className="inputgroup fx -c">
                    <InputGroup
                      placeholder="Address"
                      required={true}
                      value={mail}
                      onChange={(ev: any) => setMail(ev.currentTarget.value)}
                    />
                    <div className="fx -r">
                      <InputGroup
                          placeholder="ZipCode"
                          required={true}
                          value={mailConfirm}
                          onChange={(ev: any) =>
                              setMailConfirm(ev.currentTarget.value)
                          }
                      />
                      <InputGroup
                          placeholder="City"
                          required={true}
                          value={password}
                          onChange={(ev: any) =>
                              setPassword(ev.currentTarget.value)
                          }
                      />
                    </div>
                    <InputGroup
                        placeholder="Country"
                        required={true}
                        value={password}
                        onChange={(ev: any) =>
                            setPassword(ev.currentTarget.value)
                        }
                    />
                  </div>
                  <Button
                      className="outline-style-d"
                      icon="tick-circle"
                      type="submit"
                      disabled={!validateForm()}
                  >
                    Confirm my subscription
                  </Button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
});
